    """
    Takes in a list of tuples and returns a dictionary mapping each unique tuple to the number of times it occurs in the list.
    """
    # Create a dictionary to store the counts of each tuple
    count_dict = {}

    # Iterate over each tuple in the list
    for tuple_tuple in list_of_tuples:
        # Check if the tuple is already in the dictionary
        if tuple_tuple in count_dict:
            # Increment the count of the tuple
            count_dict[tuple_tuple] += 1
        else:
            # Add the tuple to the dictionary with a count of 1
            count_dict[tuple_tuple] = 1

    # Return the dictionary
    return count_dict

