        return 0
    else:
        count = 0
        for i in range(2, num):
            if i == 2:
                count += 1
            elif i % 2 == 0:
                continue
            else:
                for j in range(3, i, 2):
                    if i % j == 0:
                        break
                else:
                    count += 1
        return count

