def k_smallest_pairs(arr1, arr2, k):
    # Create a dictionary to store the frequency of each element in arr2
    freq = {}
    for num in arr2:
        if num in freq:
            freq[num] += 1
        else:
            freq[num] = 1

    # Create a list to store the smallest pairs
    pairs = []

    # Iterate over the elements in arr1
    for num in arr1:
        # If the frequency of num in arr2 is greater than k, skip it
        if freq[num] > k:
            continue

        # If the frequency of num in arr2 is less than or equal to k, add it to the pairs list
        if freq[num] <= k:
            pairs.append([num, freq[num]])

    # Return the smallest k pairs
    return pairs[:k]

