def max_product(arr):
    if len(arr) < 2:
        return arr
    max_product = arr[0]
    for i in range(1,len(arr)):
        if arr[i] > max_product:
            max_product = arr[i]
    for i in range(1,len(arr)):
        if arr[i] < max_product:
            max_product = arr[i]
    return max_product

